-- Enrichment marathon batch: HumHub, Hunter, Huntress, Hurl, Hydrogen, Hygraph, Hypefury, HyperDX

-- ── HumHub ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source social intranet and community platform for self-hosted or cloud team collaboration and knowledge sharing.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Professional plans from about EUR144/month for 100 users$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Munich, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$HumHub Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HumHub review 2026: open-source social intranet features, self-hosting versus cloud pricing tiers, modules, pros and cons, and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HumHub is an open-source enterprise social networking and intranet platform built to help organizations, associations, nonprofits, universities, and public institutions communicate, collaborate, and share knowledge on a single customizable network. The first code was written in February 2014 by Munich-based developer and entrepreneur Lucas Bartholemy, and the company behind it, HumHub GmbH and Co. KG, was formally established in 2015 and remains headquartered in Munich, Germany. HumHub has grown as a bootstrapped, self-funded open-source business rather than through venture capital, generating revenue through commercial licenses, managed hosting, and support contracts rather than equity financing. Technically, HumHub is built on the Yii2 PHP framework with a MySQL/MariaDB backend, and its free Community Edition is distributed under the AGPL-3.0 license, meaning anyone can download and self-host it on their own server infrastructure at no cost. The platform's architecture is modular: a lightweight social core covering activity streams, user profiles, spaces and groups, wikis, file sharing, calendars, and internal messaging can be extended with dozens of official and community-built modules available through the HumHub Marketplace, including Advanced LDAP and Active Directory sync, SAML single sign-on, Solr-powered search, custom enterprise themes, polls, task boards, and video conferencing hooks. Organizations can run HumHub entirely on their own infrastructure for full data sovereignty, which is popular with GDPR-conscious European customers, government agencies, and privacy-sensitive enterprises, or they can pay HumHub to manage cloud hosting on their behalf. Pricing follows a freemium structure: the Community Edition is completely free and open source with no user limits, while the Professional Edition adds a commercial license, direct access to the HumHub team for configuration and maintenance, guaranteed security patches, long-term support covering the two most recent major releases, and access to exclusive modules. Professional pricing is billed per user per month in bands starting around 50 users, listed from roughly EUR129 to EUR144 per month for the entry band, with optional GDPR-compliant EU hosting for about EUR36 per month and one-time onboarding packages priced between roughly EUR1,575 and EUR2,575; networks with several thousand users pay only low single-digit cents per user per month once volume discounts scale in. An Enterprise Edition is available on custom quote for deployments beyond 1,000 users, multi-site rollouts, or bespoke development work. HumHub's target audience spans mid-size and large organizations that need an internal social intranet or community platform without depending on closed SaaS incumbents: HR and internal-communications teams, membership associations, universities, NGOs, and public-sector bodies that value self-hosting and open-source auditability. Its most direct competitors include Confluence, Bitrix24, Mattermost, and other open-source intranet and community tools such as Elgg; HumHub differentiates itself through the combination of genuine open-source self-hosting, a broad extensible module ecosystem, and a lighter, more easily branded interface compared to heavier enterprise suites like SharePoint or Workplace alternatives. The company maintains a small, Munich-based core team of roughly a dozen-plus employees who handle in-house support and customer inquiries for a global base of companies, nonprofits, and public institutions using the platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5a7a7d03-38e8-4c10-aa13-d20c62a48b08';

