-- ── Hurl ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source command-line tool for running and testing HTTP requests defined in a simple plain-text format, powered by libcurl.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Issy-les-Moulineaux, France (Orange S.A.)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hurl Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hurl review 2026: open-source command-line HTTP testing tool features, plain-text syntax, CI/CD use cases, pros and cons, and Postman alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hurl is a free, open-source command-line tool for running and testing HTTP requests defined in a simple, human-readable plain-text format. It is developed and maintained by Orange, the French multinational telecommunications company, under its Orange-OpenSource organization on GitHub, where the public repository was created in August 2020. Hurl's original authors include Jean-Christophe Amiel, Fabrice Reix, and Filipe Pinto, and the project is released under the Apache License 2.0, meaning it is completely free to use, modify, and redistribute with no commercial license, subscription, or paid tier of any kind. Under the hood, Hurl is a lightweight binary written in Rust, and its HTTP engine is powered by libcurl, one of the most widely trusted and battle-tested file transfer libraries in existence, giving Hurl behavior and protocol support very close to that of the curl command itself. What differentiates Hurl from curl or a general scripting approach is its dedicated file format: a .hurl file lets a developer define one or more HTTP requests, along with expected response assertions, in plain text that can be checked directly into version control and diffed like any other source file. Requests can be chained together, with values captured from one response (such as an authentication token, a session cookie, or an ID) used to parameterize subsequent requests, enabling realistic multi-step API workflows without writing imperative code. Assertions can validate HTTP status codes, response headers, and response bodies, including structured queries against JSON via JSONPath and against XML or HTML via XPath, which makes Hurl useful not just for exploratory API calls but for genuine regression and contract testing of REST, GraphQL, and SOAP APIs. Because it ships as a single lightweight cross-platform binary for Linux, macOS, and Windows with no GUI or heavyweight runtime dependency, Hurl integrates cleanly into CI/CD pipelines, where .hurl test files can run automatically on every commit or deployment, producing structured pass/fail results and optional HTML test reports. Hurl's target audience is developers, QA engineers, and DevOps teams who want version-controllable, scriptable HTTP testing without the overhead of a full GUI application, positioning it as a lighter, text-first alternative to tools like Postman and Insomnia, and a more structured, assertion-capable alternative to raw curl scripting. Because it has no company, subscription, or funding model behind it beyond Orange's ongoing open-source sponsorship, there are no pricing tiers, editions, or paid upgrades; the entire feature set, including chaining, assertions, JSONPath and XPath querying, and CI/CD-friendly output, is available for free to every user under the same open license.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5db80a47-34dc-4c07-9969-53321dbed91e';

