-- ── HyperDX ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source observability platform unifying logs, traces, metrics, and session replay on ClickHouse and OpenTelemetry.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Starter from $20/month (50 GB included)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HyperDX Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HyperDX review 2026: open-source observability pricing, ClickHouse-powered architecture, features, pros and cons, and top alternatives compared in depth.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HyperDX is an open-source observability platform that unifies logs, traces, metrics, exceptions, and session replay in a single tool, built on OpenTelemetry for data collection and ClickHouse, the open-source columnar analytics database, for storage and querying. The company was founded in 2022 by Warren Lee and Michael Shi as a Y Combinator-backed startup headquartered in San Francisco, California, with the goal of building a developer-friendly, cost-effective alternative to observability incumbents like Datadog and New Relic by combining ClickHouse's raw query performance and storage efficiency with a purpose-built observability interface. In March 2025, ClickHouse Inc., the company behind the ClickHouse database itself, acquired HyperDX to accelerate the future of open-source observability; following the acquisition, HyperDX's technology became the foundation of 'ClickStack,' ClickHouse's official open-source observability stack, while HyperDX Cloud has continued operating and onboarding new customers as part of ClickHouse's product lineup. Architecturally, HyperDX ingests OpenTelemetry-formatted logs, traces, and metrics directly into ClickHouse, and its frontend and backend, released under MIT and Apache 2.0 licenses, provide unified search, dashboards, alerting, and session replay correlated against backend traces and events. The platform can be fully self-hosted via Docker or Kubernetes on a team's own ClickHouse cluster for complete infrastructure control, or consumed as a hosted cloud SaaS product. Core features include a unified search interface spanning logs, traces, metrics, and errors; pre-built dashboards; exception and error tracking; frontend session replay tied directly to backend traces so engineers can see exactly what a user experienced alongside the corresponding server-side errors; alerting integrations with Slack, PagerDuty, and generic webhooks; and native compatibility with the OpenTelemetry Collector, meaning teams with existing OTel instrumentation can adopt HyperDX without re-instrumenting their applications or risking vendor lock-in. Pricing is usage-based rather than per-seat or per-host, a deliberate contrast to traditional observability vendors: the Free tier includes 3 GB of data per month with 3-day retention and support for 1 user; the Starter plan costs a flat $20 per month and includes 50 GB of data per month with 30-day retention and unlimited users, with additional usage priced at $0.40 per extra GB and $0.40 per 100 metrics at 1 data point per minute; and an Enterprise tier offers custom contracts, custom retention periods, SAML single sign-on, and volume discounts for large-scale deployments. HyperDX's target audience is engineering teams, from early-stage startups to platform and SRE teams at larger companies, who want Datadog-level observability capability without Datadog's often steep per-host and per-seat pricing, and who specifically value the ability to self-host on open-source infrastructure they may already operate to control costs and avoid vendor lock-in. Named competitors include Datadog, New Relic, the Grafana LGTM stack (Loki, Grafana, Tempo, Mimir), Honeycomb, SigNoz, and Better Stack; HyperDX differentiates itself through its ClickHouse-native architecture, which enables fast aggregate queries over very large volumes of logs and traces at meaningfully lower infrastructure cost, its single unified interface spanning logs, traces, metrics, and session replay rather than siloed tools, and, following the 2025 acquisition, the ongoing engineering resources and long-term backing of ClickHouse Inc. itself.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd0fed099-679d-4702-a509-fbb8a5115476';

