INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Activity Streams and Spaces$q$, $q$Members post updates and collaborate inside dedicated spaces for teams, departments, or interest groups, similar to a private social network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Module Marketplace$q$, $q$Dozens of official and community-built modules extend the core platform with polls, tasks, video calls, custom themes, and more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Self-Hosting and Data Sovereignty$q$, $q$The Community Edition can be installed on any server the organization controls, keeping all data in-house for compliance-sensitive deployments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$File Sharing and Wiki$q$, $q$Built-in document storage and collaborative wiki pages let teams keep shared knowledge alongside the conversation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$LDAP and SAML Single Sign-On$q$, $q$Professional customers can sync users via Active Directory or LDAP and enable SAML-based SSO for enterprise identity management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Solr-Powered Search$q$, $q$An optional Solr integration provides fast, full-text search across posts, files, and wiki content network-wide.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Calendar and Task Coordination$q$, $q$Shared calendars and task modules help distributed teams coordinate schedules and work items inside the same network.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Custom Branding and Themes$q$, $q$Administrators can apply enterprise themes and custom branding so the network matches the organization's identity.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Fully open source and self-hostable for complete control over data and infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Highly modular and extensible through an active marketplace of official and community modules$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$No per-user licensing cost for the Community Edition, even at large scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$GDPR-compliant EU hosting option appeals to privacy-conscious European organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Long-running, actively maintained project with regular releases since 2015$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Interface feels more utilitarian than modern venture-funded SaaS competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Self-hosting requires in-house technical resources to install, secure, and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Professional support and exclusive modules add meaningful per-user cost at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Smaller community and plugin ecosystem than larger platforms like Mattermost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Native mobile apps are less polished than those of better-funded rivals$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Is HumHub free to use?$q$, $q$Yes. The Community Edition is completely free and open source under the AGPL-3.0 license, and it can be self-hosted with no user limits. Paid Professional and Enterprise editions add vendor support, guaranteed patches, and exclusive modules.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Can I self-host HumHub?$q$, $q$Yes, HumHub is designed to be self-hosted on your own server infrastructure using PHP, MySQL or MariaDB, and the Yii2 framework, giving you full control over your data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$What is the difference between the Community and Professional editions?$q$, $q$The Community Edition is free and open source with community support only. The Professional Edition adds a commercial license, direct vendor support, guaranteed security patches, long-term release support, and exclusive modules like Advanced LDAP and SAML SSO.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Does HumHub support single sign-on?$q$, $q$Yes, Professional and Enterprise customers can enable SAML-based single sign-on and LDAP or Active Directory synchronization for centralized identity management.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Is HumHub GDPR compliant?$q$, $q$HumHub offers an optional GDPR-compliant EU hosting add-on with daily backups, and self-hosting gives organizations full control over data residency and compliance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$What technology is HumHub built on?$q$, $q$HumHub is built on the Yii2 PHP framework with a MySQL or MariaDB database backend, and its Community Edition source code is publicly available on GitHub.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Internal Company Intranet$q$, $q$Replace scattered email threads and chat channels with a unified internal network for announcements, documents, and team spaces.$q$, $q$HR and internal communications teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Association and Nonprofit Community Platform$q$, $q$Give members a branded space to discuss, share files, and coordinate events without paying per-seat SaaS fees.$q$, $q$Membership associations and nonprofits$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$University and Education Collaboration Network$q$, $q$Support course groups, research collaboration, and campus-wide communication on infrastructure the institution controls.$q$, $q$Universities and educational institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open source, self-hosted","Unlimited users","Core social intranet features","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Professional Edition$q$, $q$From about EUR144/month for 100 users$q$, $q$Monthly or annual$q$, NULL, $q$["Commercial license","Direct vendor support","Guaranteed security patches","Exclusive modules (LDAP, SAML SSO, Solr)","Optional GDPR-compliant EU hosting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$Enterprise Edition$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["For 1,000+ users","Multi-site deployments","Custom development","Dedicated account management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HumHub is an open-source social networking and intranet kit designed for organizations that want a customizable internal community without being locked into a closed SaaS vendor. Founded in Munich, Germany in 2015 and building on code first written in 2014 by Lucas Bartholemy, the project is distributed under the AGPL-3.0 license and can be freely downloaded, self-hosted, and modified by anyone with server infrastructure.$q$, $q$At its core, HumHub provides activity streams, spaces and groups, wikis, file sharing, calendars, and messaging in a single lightweight PHP application built on the Yii2 framework. Because the core is intentionally minimal, most of the platform's power comes from its module marketplace, which lets administrators bolt on identity management, search, theming, and workflow tools as their organization's needs grow.$q$, $q$HumHub is used by companies, nonprofits, associations, universities, and government bodies worldwide, particularly organizations in Europe that prioritize GDPR compliance and data sovereignty over the convenience of a fully managed SaaS platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HumHub's social core mirrors familiar consumer social networks: members post updates, join topic- or team-based spaces, co-edit wiki pages, share files, and coordinate through shared calendars and internal messaging. Administrators can fully rebrand the interface, control visibility and permissions at a granular level, and organize the network into multiple spaces for departments, projects, or interest groups.$q$, $q$The module marketplace is what separates HumHub from a simple message board: paid Professional customers gain access to Advanced LDAP and Active Directory synchronization, SAML-based single sign-on, Solr-powered enterprise search, custom enterprise themes, and other modules that make HumHub viable as a primary corporate intranet rather than just a community add-on.$q$, $q$Deployment flexibility is a defining feature. Organizations can self-host the free Community Edition entirely on their own servers for maximum control, opt into HumHub's GDPR-compliant EU-based managed hosting for a monthly fee, or engage HumHub's team directly for onboarding, configuration, and long-term support under the Professional or Enterprise tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HumHub uses a freemium model built around three tiers. The Community Edition is entirely free and open source with no user caps, making it a genuine option for budget-conscious organizations willing to handle their own hosting and maintenance. The Professional Edition introduces a commercial license, guaranteed security patches, direct vendor support, and exclusive modules, billed per user per month in bands that start around 50 users, from roughly EUR129 to EUR144 per month for the entry band, with per-user costs shrinking substantially as the network scales into the thousands.$q$, $q$Optional add-ons include GDPR-compliant EU hosting for about EUR36 per month and one-time onboarding packages priced between roughly EUR1,575 and EUR2,575, both quoted before VAT. Organizations with more than 1,000 users, multi-site requirements, or custom development needs move to the Enterprise Edition, which is quoted individually based on scale and configuration rather than published as a fixed price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
