INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a7a7d03-38e8-4c10-aa13-d20c62a48b08', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
