INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Domain Search$q$, $q$Find every publicly associated email address and pattern for a given company domain in one search.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Email Finder$q$, $q$Predict the most likely professional email address for a specific person at a specific company.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Email Verifier$q$, $q$Check syntax, domain validity, and deliverability before sending to reduce bounce rates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Hunter Campaigns$q$, $q$Build and send simple cold email sequences with follow-ups and open tracking directly in Hunter.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Chrome Extension$q$, $q$Find and verify emails directly on company websites and LinkedIn profiles without leaving the page.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$CRM and Workflow Integrations$q$, $q$Native connections to HubSpot, Salesforce, Pipedrive, Google Sheets, and Zapier for streamlined prospecting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$REST API$q$, $q$Programmatic access to Domain Search, Email Finder, and Email Verifier for custom enrichment workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Hunter Discover$q$, $q$Find companies matching specific criteria to build targeted prospect lists.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Generous free tier lets individuals test the product before committing to a paid plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Strong reputation for email deliverability accuracy and low bounce rates$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Simple, transparent credit-based pricing that is easy to forecast$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Convenient Chrome extension speeds up prospecting directly on target websites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Deep integrations with major CRMs and Zapier for workflow automation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Credits can be consumed quickly during heavy prospecting campaigns$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$No phone number data is offered, unlike some all-in-one prospecting competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Higher tiers become expensive for larger sales teams needing high volume$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Occasional false positives or gaps on smaller or newer company domains$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Built-in outreach features are more basic than dedicated sales engagement platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Is Hunter free to use?$q$, $q$Yes, Hunter offers a free plan with 50 monthly credits and no credit card required. Paid plans start at $34 per month billed annually for higher credit volumes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$What is a Hunter credit?$q$, $q$A credit is Hunter's usage unit. Finding an email through Domain Search or Email Finder costs one credit, while verifying an email costs half a credit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Does Hunter verify email addresses?$q$, $q$Yes, Hunter's Email Verifier checks syntax, domain validity, and mailbox deliverability to help reduce bounce rates before you send outreach.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Does Hunter offer an API and integrations?$q$, $q$Yes, Hunter provides a full REST API plus native integrations with HubSpot, Salesforce, Pipedrive, Google Sheets, and Zapier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Who founded Hunter?$q$, $q$Hunter was founded in 2015 by Antoine Finkelstein and François Grante, and the company has grown without raising outside venture funding.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$How is Hunter different from Apollo.io?$q$, $q$Hunter focuses specifically on email finding and verification with simple credit-based pricing, while Apollo.io bundles a broader sales engagement platform including phone data, dialers, and sequencing at a higher price point.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Sales Prospecting$q$, $q$Find and verify decision-maker email addresses before launching outbound outreach campaigns.$q$, $q$SDRs and business development reps$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Recruiting Outreach$q$, $q$Locate candidate contact details to reach passive talent outside of job boards.$q$, $q$Recruiters and talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Journalist and Partnership Outreach$q$, $q$Find verified contact emails for media, partnership, or link-building outreach.$q$, $q$Marketers, PR professionals, and founders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["50 credits/month","No credit card required","Chrome extension access","Basic API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Starter$q$, $q$$34/month billed annually ($49 billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Higher monthly credit volume","Unlimited seats","Email support","CRM integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Growth$q$, $q$About $104/month billed annually$q$, $q$Annual$q$, NULL, $q$["Increased credits and API limits","Hunter Campaigns access","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$Scale$q$, $q$About $244/month billed annually$q$, $q$Annual$q$, NULL, $q$["Highest self-serve credit volume","Advanced API limits","Dedicated account support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hunter is an email finder and verifier built to solve one specific problem for sales, marketing, and recruiting professionals: quickly and reliably determining a person's professional email address at a given company. Founded in 2015 by Antoine Finkelstein and François Grante, the company has grown into a widely used prospecting tool without ever raising outside venture funding, operating instead as a lean, fully remote, self-funded business.$q$, $q$The product's underlying database is built from publicly indexed data across roughly 81 million websites, which powers its core Domain Search and Email Finder features. Users can search by company domain to see every publicly associated email pattern and contact, or search by a specific name and domain to generate the most likely email address, which is then checked for deliverability through Hunter's Email Verifier.$q$, $q$Hunter is delivered as a web app, a Chrome extension, a Google Sheets add-on, and a full REST API, making it easy to slot into existing prospecting and CRM workflows rather than requiring teams to change how they already work.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hunter's core toolset centers on Domain Search, which returns every email address pattern and publicly associated contact for a given company domain, and Email Finder, which predicts a specific person's most likely email address given their name and company. Both are backed by the Email Verifier, which checks syntax, domain validity, and mailbox deliverability to reduce bounce rates before a user sends outreach.$q$, $q$For teams running structured outreach, Hunter Campaigns adds the ability to build and send simple cold email sequences with follow-ups and open tracking directly from the platform, reducing the need for a separate sales engagement tool for smaller-scale outreach.$q$, $q$Integration depth is a major part of Hunter's value: the platform connects natively to HubSpot, Salesforce, Pipedrive, and Zapier, and exposes a full API for teams building custom prospecting or enrichment workflows, alongside a widely used Chrome extension for finding contacts directly on company websites and LinkedIn.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hunter uses a straightforward credit-based pricing model across five tiers. The Free plan includes 50 credits per month with no credit card required, letting individuals and very small teams try the product with no commitment. Paid tiers start at the Starter plan, priced at $49 per month billed monthly or $34 per month billed annually, and scale up through Growth at roughly $104 per month and Scale at roughly $244 per month with annual billing, each unlocking more monthly credits, higher API limits, and additional seats.$q$, $q$One credit finds an email via Domain Search or Email Finder, while verifying an email costs half a credit, and unlimited team members are included on every paid plan rather than being charged per seat. Annual billing applies a flat roughly 30 percent discount versus monthly pricing across all tiers, and an Enterprise plan with custom pricing and contract terms is available for larger sales and revenue teams that need higher volume or dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('572625cb-f9cb-4961-b33c-f1f81f45c14d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
