INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed EDR$q$, $q$Endpoint detection and response with lightweight agents and human-verified threat investigation on Windows and macOS.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$24/7 Security Operations Center$q$, $q$Human threat analysts monitor and triage alerts around the clock, escalating only validated incidents to reduce alert fatigue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed ITDR$q$, $q$Identity threat detection and response covering Microsoft 365 and Active Directory compromise and account takeover attempts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed SIEM$q$, $q$Centralized log monitoring and event correlation for broader visibility and compliance reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed Security Awareness Training$q$, $q$Phishing simulations and employee training built on the acquired Curricula platform to reduce human-error risk.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Ransomware Canaries$q$, $q$Decoy files that trigger immediate alerts when ransomware begins encrypting a system, enabling faster containment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$MSP Multi-Tenant Dashboard$q$, $q$A unified console lets MSPs monitor and manage security across all client environments from one place.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Incident Response Guidance$q$, $q$Verified incidents come with clear, actionable remediation steps rather than raw alert data alone.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Transparent, flat per-endpoint pricing with no long-term enterprise contract required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$24/7 human-led SOC monitoring included standard rather than as a paid add-on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$No minimum endpoint requirement, making it accessible to very small businesses and solo MSPs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Strong reputation and loyal following within the MSP community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Fast, clear incident response guidance reduces the burden on small IT teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Historically endpoint-centric, with network and cloud coverage still maturing relative to legacy competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Costs can add up quickly once ITDR, SIEM, and training products are layered together$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Less proven at very large enterprise scale compared to CrowdStrike or SentinelOne$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Requires stacking multiple product lines to get full-stack coverage rather than one bundled suite$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Initial setup and agent deployment can take time for MSPs onboarding many client environments at once$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$How much does Huntress cost?$q$, $q$Huntress's flagship Managed EDR product starts at $8.99 per endpoint per month, with 24/7 SOC monitoring included. Other products like Managed ITDR, SIEM, and Security Awareness Training are priced separately based on configuration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Is Huntress EDR or MDR?$q$, $q$Huntress is best described as managed EDR combined with MDR-style human SOC monitoring, since every subscription includes 24/7 threat hunting and remediation guidance from human analysts rather than just automated alerts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Who founded Huntress?$q$, $q$Huntress was founded in 2015 by Kyle Hanslovan, Chris Bisnett, and John Ferrell, three former NSA cyber operators, and is headquartered in Columbia, Maryland.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Is Huntress a public company?$q$, $q$No, Huntress is a privately held company that reached a valuation above $1.5 billion after its $150 million Series D round in 2024, led by Kleiner Perkins.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Does Huntress replace existing antivirus software?$q$, $q$Huntress is designed to work alongside existing antivirus and endpoint protection tools, adding a layer of human-verified threat detection and response rather than replacing baseline AV entirely.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Is Huntress suitable for large enterprises?$q$, $q$Huntress primarily targets SMBs and the MSPs that serve them; very large enterprises with dedicated in-house security teams often evaluate it alongside enterprise-focused platforms like CrowdStrike or SentinelOne.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$MSP Client Fleet Protection$q$, $q$Monitor and secure endpoints across multiple client organizations from a single multi-tenant dashboard.$q$, $q$Managed service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$SMB Security Without an In-House SOC$q$, $q$Get 24/7 human threat monitoring without hiring a dedicated security operations team.$q$, $q$Small and mid-sized business IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Identity and Credential Threat Detection$q$, $q$Detect compromised Microsoft 365 and Active Directory accounts before attackers escalate access.$q$, $q$IT administrators managing cloud identity$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed EDR$q$, $q$From $8.99/endpoint/month$q$, $q$Monthly$q$, NULL, $q$["24/7 human SOC monitoring","Ransomware canaries","Incident remediation guidance","No minimum endpoint requirement"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed ITDR$q$, $q$Custom, per user$q$, $q$Custom$q$, NULL, $q$["Microsoft 365 and Active Directory monitoring","Account takeover detection","Identity-focused threat hunting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$Managed SIEM$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Centralized log monitoring","Compliance-relevant event correlation","Extended detection coverage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$MSP/Enterprise Bundle$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Multi-tenant management","Volume-based discounts","Combined EDR, ITDR, SIEM and training"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Huntress is a managed cybersecurity platform purpose-built for small and mid-sized businesses and the managed service providers who protect them, an underserved market segment relative to enterprise-focused security vendors. Founded in 2015 by three former NSA cyber operators, Kyle Hanslovan, Chris Bisnett, and John Ferrell, the company is headquartered in Columbia, Maryland, and has scaled from a $50,000 accelerator seed check into a unicorn valued above $1.5 billion.$q$, $q$The platform's defining characteristic is that every subscription includes 24/7 monitoring from a human-staffed security operations center rather than relying solely on automated detection, which reduces false positives and lets small IT teams or solo MSP operators respond to genuinely validated threats instead of chasing every algorithmic alert.$q$, $q$Huntress has expanded well beyond its original endpoint detection roots into identity threat detection, SIEM, and security awareness training, most notably through its 2022 acquisition of the Curricula training platform, positioning it as a broader managed security stack rather than a single-product EDR tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Managed EDR is Huntress's flagship product, deploying lightweight agents to Windows and macOS endpoints that feed telemetry into Huntress's detection engine, where human analysts investigate suspicious activity, persistent footholds, and ransomware behavior before escalating verified incidents with clear remediation guidance.$q$, $q$Managed ITDR extends protection into identity infrastructure, particularly Microsoft 365 and Active Directory, detecting compromised credentials and account takeover attempts that endpoint-only tools miss, while Managed SIEM centralizes log data for threat correlation and compliance reporting.$q$, $q$Managed Security Awareness Training, built on the acquired Curricula platform, rounds out the stack with phishing simulations and employee training designed to reduce the human-error attack surface that technical controls alone cannot close.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6519e387-8e19-4973-8093-cbf36862242e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Huntress prices its flagship Managed EDR product transparently at $8.99 per endpoint per month, with 24/7 SOC monitoring, threat hunting, and remediation guidance included as standard rather than charged as a separate premium tier. This differs meaningfully from competitors like CrowdStrike, which has historically required a 300-endpoint minimum for managed services and often prices support separately, making Huntress notably more accessible to very small IT departments and independent MSPs managing only a handful of client endpoints.$q$, $q$Additional product lines, Managed ITDR, Managed SIEM, and Managed Security Awareness Training, are typically priced per user or per endpoint and quoted based on the combination of products a customer or MSP selects, with volume-based discounts available for larger endpoint counts and MSP partners managing multiple client tenants. Enterprise and MSP partner agreements are generally negotiated directly with Huntress's sales team rather than published as fixed self-serve pricing.$q$]::text[], 2);
