INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Plain-Text HTTP Request Format$q$, $q$Define HTTP requests and expected responses in simple, version-controllable .hurl text files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Built-In Assertions$q$, $q$Validate status codes, headers, and response bodies, including JSONPath and XPath queries, without extra tooling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Request Chaining and Captures$q$, $q$Capture values from one response and reuse them in later requests to model realistic multi-step API flows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$libcurl-Powered Engine$q$, $q$Built on libcurl for protocol behavior and reliability very close to the curl command itself.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$CI/CD-Friendly Output$q$, $q$Structured pass/fail results and optional HTML test reports make Hurl easy to wire into automated pipelines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$REST, GraphQL, and SOAP Support$q$, $q$Works across common API styles, not just simple REST endpoints.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Cross-Platform Single Binary$q$, $q$Runs identically on Linux, macOS, and Windows with no GUI or heavyweight runtime dependency.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Version-Controllable Test Files$q$, $q$Because tests are plain text, they can be reviewed in pull requests and diffed like application code.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Completely free and open source with no paid tiers or limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Lightweight single binary with no scripting language or GUI required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Powerful built-in assertions make it a genuine API testing tool, not just a request runner$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Plain-text format is easy to version control, review, and diff$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Backed and actively maintained by Orange with a stable release history since 2020$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Smaller plugin and template ecosystem compared to Postman or Insomnia$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$No polished graphical interface, which can be a barrier for non-technical testers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Steeper learning curve for complex chained scenarios compared to point-and-click tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Limited built-in mocking or virtualization capabilities$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Less mainstream brand recognition than established API tools like Postman$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$What is Hurl?$q$, $q$Hurl is an open-source command-line tool that runs and tests HTTP requests defined in a simple plain-text format, built by Orange and powered by libcurl.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Is Hurl free?$q$, $q$Yes, Hurl is completely free and open source under the Apache License 2.0, with no paid tiers, subscriptions, or usage limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Who maintains Hurl?$q$, $q$Hurl is developed and maintained by Orange, the French telecommunications company, under its Orange-OpenSource organization on GitHub, with original contributions from Jean-Christophe Amiel, Fabrice Reix, and Filipe Pinto.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Can Hurl replace Postman or curl?$q$, $q$Hurl can replace many curl scripting use cases and offers more structured, testable workflows than raw curl, though it lacks Postman's graphical interface and collaboration features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Does Hurl support CI/CD pipelines?$q$, $q$Yes, Hurl is designed to integrate cleanly into CI/CD pipelines, producing structured pass/fail results and optional HTML test reports for automated testing on every build.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$What platforms and protocols does Hurl support?$q$, $q$Hurl runs on Linux, macOS, and Windows, and supports REST, GraphQL, and SOAP APIs, with assertion support for JSON via JSONPath and XML or HTML via XPath.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$API Testing in CI/CD Pipelines$q$, $q$Run automated HTTP assertion tests on every commit or deployment as part of a build pipeline.$q$, $q$Developers and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Quick HTTP Request Scripting$q$, $q$Script and chain HTTP requests in plain text for debugging or exploring an API without writing code.$q$, $q$Backend developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Contract and Regression Testing$q$, $q$Maintain version-controlled test suites that validate REST and GraphQL API responses over time.$q$, $q$QA and test engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set with no limits","Request chaining and assertions","JSONPath and XPath support","CI/CD-friendly output","Cross-platform binary"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hurl is an open-source command-line tool that runs and tests HTTP requests defined in a simple plain-text file format. Developed by Orange under its Orange-OpenSource GitHub organization since 2020, Hurl is written in Rust and powered by libcurl, giving it protocol behavior close to curl itself while adding a structured, testable request format on top.$q$, $q$Rather than writing imperative scripts or clicking through a GUI, Hurl users define requests, headers, bodies, and expected assertions in a .hurl file that can be committed to version control, reviewed in pull requests, and diffed like any other source code, which appeals strongly to developers who want their API tests to live alongside their application code.$q$, $q$Because it ships as a single lightweight binary with no GUI dependency, Hurl is particularly well suited to CI/CD pipelines, where test suites can run automatically on every build with clear structured output.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hurl supports chaining multiple requests together within a single file, capturing values like authentication tokens, cookies, or IDs from one response and injecting them into subsequent requests, which makes it possible to model realistic multi-step API flows such as login-then-fetch-then-update sequences entirely in plain text.$q$, $q$Its assertion system covers HTTP status codes, response headers, and response bodies, with support for JSONPath queries against JSON APIs and XPath queries against XML or HTML responses, allowing Hurl to function as a genuine regression and contract-testing tool rather than just a request runner.$q$, $q$Hurl works across REST, GraphQL, and SOAP APIs, runs identically on Linux, macOS, and Windows, and produces both terminal output and optional HTML test reports, making it straightforward to wire into CI/CD systems for automated API testing on every commit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hurl is entirely free and open source under the Apache License 2.0, with no company, subscription, or paid tier attached to it. There is no freemium gate, no usage limit, and no enterprise edition; the full feature set, including request chaining, assertions, JSONPath and XPath querying, and CI/CD-friendly reporting, is available to every user at no cost.$q$, $q$Because Hurl is maintained by Orange as a sponsored open-source project rather than a commercial product, there is no vendor to negotiate pricing with; organizations simply download the binary or install it via common package managers and use it under the terms of its open-source license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5db80a47-34dc-4c07-9969-53321dbed91e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
