INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Pattern-Based Step Sequencer$q$, $q$Program drum patterns instrument by instrument across an unlimited number of patterns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Song Editor$q$, $q$Chain individual patterns together to arrange complete song structures.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Built-In Mixer and Effects$q$, $q$Control per-instrument volume, pan, and sends, with built-in reverb and delay effects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$MIDI Input and Output$q$, $q$Play and record drum patterns live using external MIDI controllers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$LADSPA and LV2 Plugin Support$q$, $q$Extend built-in effects processing with third-party audio plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$JACK Audio Integration$q$, $q$Route audio at low latency alongside other JACK-compatible applications on Linux.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Custom Drumkit Support$q$, $q$Load or build fully custom drumkits from multi-layered velocity samples.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Cross-Platform Availability$q$, $q$Runs natively on Linux, macOS, and Windows using the Qt GUI toolkit.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Completely free and open source with no subscription or license fees ever$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Deep, long-standing MIDI and audio plugin support for a free tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Active, long-running community development spanning more than two decades$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Lightweight and runs well even on modest or older hardware$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Strong option for Linux users who lack access to major commercial drum software$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Interface looks dated compared to modern commercial DAWs and drum plugins$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Steeper learning curve for newcomers unfamiliar with pattern-based sequencers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Smaller built-in drumkit library than commercial competitors like Superior Drummer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Primarily sample-based rather than offering advanced physical modeling synthesis$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Less polished experience on Windows and macOS compared to its native Linux environment$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Is Hydrogen free?$q$, $q$Yes, Hydrogen is completely free and open source under the GPL-2.0-or-later license, with no paid tiers or subscription of any kind.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$What platforms does Hydrogen support?$q$, $q$Hydrogen runs natively on Linux, macOS, and Windows using the Qt graphical toolkit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Who created Hydrogen?$q$, $q$Hydrogen was created by Italian developer Alessandro Cominu, known online as Comix, with the project dating back to 2002, and it is now maintained by a community of open-source contributors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Can Hydrogen use audio plugins?$q$, $q$Yes, Hydrogen supports LADSPA and LV2 audio plugins in addition to its built-in reverb and delay effects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Does Hydrogen support MIDI controllers?$q$, $q$Yes, Hydrogen offers full MIDI input and output support so users can play and record drum patterns live from external hardware controllers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Is Hydrogen still actively maintained?$q$, $q$Yes, Hydrogen remains actively maintained by community contributors on GitHub under the hydrogen-music organization, with regular releases continuing more than two decades after the project began.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Home Studio Drum Programming$q$, $q$Program realistic drum patterns for songs and demos without buying commercial drum software.$q$, $q$Musicians and home studio producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Linux Audio Production$q$, $q$Get professional-grade drum machine functionality with native JACK integration on Linux.$q$, $q$Linux-based musicians and producers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Live MIDI Drum Performance$q$, $q$Play and record drum parts live using MIDI controllers routed into Hydrogen's sound engine.$q$, $q$Live performers and electronic musicians$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full sequencer and mixer","Built-in effects","MIDI input/output","LADSPA/LV2 plugin support","Custom drumkit support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hydrogen is a free, open-source, advanced drum machine and step sequencer created by Italian developer Alessandro Cominu, with roots tracing back to 2002. It is a community-maintained project released under the GPL-2.0-or-later license, meaning anyone can download, use, and modify it without cost or licensing restrictions.$q$, $q$The software runs natively on Linux, macOS, and Windows via the Qt GUI toolkit, and combines a pattern-based sequencer with a sample-based drum synthesizer, letting musicians program realistic drum parts instrument by instrument and arrange them into full songs.$q$, $q$Hydrogen has become a staple of the free and open-source audio production world, particularly on Linux where dedicated professional-grade drum machine software has historically been limited compared to commercial platforms available on Windows and macOS.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Hydrogen offers a pattern-based step sequencer with an unlimited number of patterns that can be chained together in a dedicated song editor, alongside a mixer providing per-instrument volume, pan, and effect send control with built-in reverb and delay.$q$, $q$Full MIDI input and output support lets users play and record drum parts live from hardware controllers, while LADSPA and LV2 plugin support extends the built-in effects with third-party processing, and JACK integration on Linux enables professional low-latency routing alongside other audio applications.$q$, $q$Hydrogen ships with a range of downloadable drumkits covering rock, jazz, electronic, and percussion styles, and supports fully custom multi-layered velocity-sampled drumkits, with an active community sharing additional kits online.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hydrogen is entirely free and open source under the GPL-2.0-or-later license, with no company, subscription, or paid tier of any kind. Every feature, including the sequencer, mixer, effects, MIDI support, and plugin compatibility, is available to every user at no cost, and there is no premium edition or upgrade path to purchase.$q$, $q$Because Hydrogen is a volunteer-maintained open-source project rather than a commercial product, funding for its development comes from community contributions and donations rather than sales, and there are no pricing tiers to compare.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4193fcc0-5bf7-41df-a6ae-52733d63e797', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
