INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Visual Schema Builder$q$, $q$Define content models and relationships through a no-code visual interface rather than raw configuration files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Content Federation$q$, $q$Connect remote sources like Shopify, Stripe, or other APIs into one unified, queryable content graph.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$GraphQL and REST APIs$q$, $q$Query content through a native GraphQL API or REST endpoints, plus webhooks for automation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Localization and Multi-Locale Support$q$, $q$Manage content across multiple languages and regions within the same content model.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Role-Based Workflows$q$, $q$Assign content, leave comments, and control permissions with granular role-based access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Scheduled Publishing$q$, $q$Plan and automate content releases for specific future dates and times.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Asset Management with Image Transformations$q$, $q$Store, organize, and transform images on the fly directly through the content API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$App and Webhook Marketplace$q$, $q$Extend Hygraph's core functionality with pre-built apps and custom webhook integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$True GraphQL-native API design reduces overfetching compared to REST-based CMS platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Unique Content Federation feature unifies multiple backend services into one content graph$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Genuinely usable free Hobby tier for small production projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$MACH-certified composable architecture appeals to enterprise engineering teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Strong multi-locale and localization support for global content teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Steep price jump from the free Hobby tier to the $199/month Growth plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$GraphQL learning curve for teams and developers used to REST-based CMS platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Advanced federation and enterprise features are gated behind custom Enterprise pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Fewer pre-built page templates than page-builder-style CMS competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Smaller third-party plugin ecosystem than more established platforms like Contentful$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$What is Hygraph?$q$, $q$Hygraph is a GraphQL-native headless content management system and content federation platform that lets teams manage structured content and unify data from third-party APIs into one queryable graph.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Is Hygraph free to use?$q$, $q$Yes, Hygraph offers a free Hobby plan that includes 1,000 content entries, 500,000 API calls per month, and 3 seats, suitable for small projects.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$What was Hygraph called before?$q$, $q$Hygraph was originally launched as GraphCMS in 2017 and rebranded to Hygraph around 2022 alongside the launch of its Content Federation platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$What is Content Federation?$q$, $q$Content Federation is Hygraph's feature that lets teams connect external APIs and services, such as Shopify or Stripe, as remote sources so their data becomes queryable alongside editorial content in one unified content graph.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Does Hygraph support GraphQL and REST?$q$, $q$Yes, Hygraph exposes a native GraphQL API as its primary interface, with REST endpoint and webhook support also available.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Who are Hygraph's main competitors?$q$, $q$Hygraph's closest competitors include Contentful, Sanity, Storyblok, Contentstack, and the open-source, self-hostable Strapi.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Composable Commerce Content Backend$q$, $q$Federate product, pricing, and inventory data from commerce platforms alongside editorial content.$q$, $q$E-commerce and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Multi-Brand and Multi-Locale Content Management$q$, $q$Manage localized content across many brands, regions, and languages from a single content model.$q$, $q$Enterprise marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Federating Multiple APIs Into One Content Graph$q$, $q$Unify data from several backend services into a single GraphQL API for frontend teams to query.$q$, $q$Platform and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1,000 entries","500,000 API calls/month","3 seats","100 GB asset traffic","Live preview and commenting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Growth$q$, $q$$199/month$q$, $q$Monthly$q$, NULL, $q$["10,000 entries","1,000,000 API calls/month","10 seats","One remote source connection","14-day version retention","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["1,000,000+ entries","50,000,000+ API calls","200 seats","10 remote source connections","SSO and audit logs","Up to 99.95% uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hygraph is a GraphQL-native headless content management system founded in 2017 in Berlin as GraphCMS by Daniel Winter and Michael Lukaszczyk, later rebranded to Hygraph around 2022 alongside the launch of its Content Federation platform. It was among the first headless CMS products built GraphQL-first rather than adding GraphQL as a layer on top of a REST-based system.$q$, $q$The platform has raised roughly $43.7 million across Series A and Series B funding rounds, funding that has been used to expand from a straightforward content API into a broader content federation platform capable of unifying multiple backend systems into one queryable graph.$q$, $q$Hygraph is MACH-certified and used by more than 50,000 projects, including recognizable brands such as Dr. Oetker, Philips, Samsung, and Ashley Furniture, reflecting its positioning as an enterprise-ready composable content backend.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Hygraph offers a visual, no-code schema builder for defining content models, paired with a single GraphQL API (plus REST and webhook support) that lets frontend teams query exactly the data fields they need without overfetching, a common pain point with REST-based CMS platforms.$q$, $q$Its standout feature is Content Federation, which lets teams connect 'remote sources,' such as Shopify, Stripe, other CMS platforms, or custom APIs, so that third-party or programmatically generated data becomes queryable alongside editorial content through one unified content graph rather than requiring separate integrations on the frontend.$q$, $q$Editorial and workflow tooling rounds out the platform: role-based permissions, commenting and content assignment, multi-locale localization, scheduled publishing, live preview, and on-the-fly image transformations support both technical and non-technical teams working in the same system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b211eaab-26f2-46f7-b63b-6470f8655fa2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hygraph offers a genuinely usable free Hobby tier, including 1,000 content entries, 500,000 API calls per month, 3 seats, and 100 GB of asset traffic, making it realistic to launch a small production project without paying anything. Stepping up to the Growth plan at $199 per month unlocks 10 seats, 10,000 entries, 1,000,000 API calls, one remote source connection for federation, and email support.$q$, $q$Larger organizations move to the custom-priced Enterprise tier, which scales limits dramatically, up to 1,000,000-plus entries, 50,000,000-plus API calls, 200 seats, 10 remote source connections, dedicated infrastructure, SSO, audit logs, and an uptime SLA up to 99.95 percent, with pricing negotiated directly based on scale and required features.$q$]::text[], 2);
