INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Inspiration Template Library$q$, $q$Access content templates spanning more than 15 niches to overcome writer's block.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Gumroad Monetization Integration$q$, $q$Connect Gumroad to weave product promotion directly into the social content workflow.$q$, 7);
