INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Auto-DM and engagement automation can risk platform terms-of-service issues if overused$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$No dedicated native mobile app for scheduling on the go$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Does Hypefury have a free plan?$q$, $q$No, Hypefury does not offer a perpetual free plan. It offers a 7-day free trial with no credit card required before requiring a paid subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Which social platforms does Hypefury support?$q$, $q$Hypefury supports X/Twitter, LinkedIn, Instagram, Facebook, TikTok, Threads, Bluesky, and Gumroad for monetization integration.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Who founded Hypefury?$q$, $q$Hypefury was founded in December 2019 by Samy Dindane and Yannick Veys, who met on Indie Hackers and bootstrapped the company into a seven-figure remote business.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$What is the Evergreen feature in Hypefury?$q$, $q$Evergreen is a content recycling feature that automatically re-shares a user's top-performing posts on a rotating schedule so they don't have to manually repost old content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Is there an agency or team plan for Hypefury?$q$, $q$Yes, Hypefury offers a Business plan at $97 per month and an Agency plan at $150 per month, which supports up to 15 X accounts and client-management features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$What is Hypefury's cheapest plan?$q$, $q$The Starter plan is Hypefury's cheapest paid tier at $29 per month, including up to 6 connected social accounts and basic Engagement Builder features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$X/Twitter Audience Growth$q$, $q$Automate scheduling, recycling, and engagement to grow a following on X/Twitter consistently.$q$, $q$Solo creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Content Repurposing Across Platforms$q$, $q$Turn a single tweet or thread into LinkedIn carousels, Instagram images, and Reels-ready formats.$q$, $q$Newsletter writers and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Agency Social Management$q$, $q$Manage scheduling and engagement automation across multiple client accounts from one dashboard.$q$, $q$Social media agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Starter$q$, $q$$29/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Up to 6 social accounts (1 X account)","About 1-month scheduling horizon","Engagement Builder (30 users, 5 keywords)","Auto-DM"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Creator$q$, $q$$65/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Unlimited scheduling","More connected accounts","Most popular plan","Full automation suite"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Business$q$, $q$$97/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Expanded account limits","Advanced analytics","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$Agency$q$, $q$$150/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Up to 15 X accounts","Client management features","Highest automation limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hypefury is a social media scheduling and growth automation tool built primarily around X/Twitter, with cross-posting support for LinkedIn, Instagram, Facebook, TikTok, Threads, Bluesky, and Gumroad. It was founded in December 2019 by Samy Dindane and Yannick Veys, who met through Indie Hackers and bootstrapped the product from a weekend MVP into a seven-figure remote business.$q$, $q$The platform is designed for individual creators and small teams who want to grow an audience on X/Twitter without spending hours each day manually posting, recycling content, and engaging with followers. Notable creators including Ali Abdaal, Justin Welsh, and Dickie Bush are cited among its user base, reflecting its popularity in the creator-economy and personal-branding space.$q$, $q$Rather than acting as a generic multi-platform scheduler, Hypefury leans heavily into X/Twitter-specific growth mechanics, offering automation features like evergreen post recycling and engagement building that are tailored to how growth happens on that platform specifically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Hypefury lets users compose content once and schedule or cross-post it across connected accounts, with an Evergreen queue that automatically re-shares top-performing posts on a rotating schedule, saving creators the manual effort of digging up and reposting older high-performing content.$q$, $q$The Engagement Builder automates growth activities like tracking specific keywords and accounts for auto-engagement, alongside auto-DM functionality for outreach, while the built-in AI post generator and a template library spanning more than 15 content niches help creators overcome writer's block and maintain a consistent posting cadence.$q$, $q$Content repurposing tools, including Tweet-to-Reels and Tweetshot-style image conversion plus LinkedIn carousel creation, let a single piece of content get reformatted and redistributed across multiple platforms, and analytics dashboards track follower growth, impressions, and engagement to show what's working.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hypefury does not offer a perpetual free plan; every new user starts with a 7-day free trial requiring no credit card before choosing one of four paid monthly tiers. The Starter plan costs $29 per month and includes up to 6 connected social accounts (including 1 X account), roughly a 1-month scheduling horizon, and Engagement Builder tracking for up to 30 users and 5 keywords, while the Creator plan at $65 per month is positioned as the most popular option with unlimited scheduling and more connected accounts.$q$, $q$Higher tiers scale up for teams and agencies: the Business plan runs $97 per month, and the Agency plan runs $150 per month with support for up to 15 X accounts and client-management features suited to agencies managing content for multiple creators. Annual billing is available across every tier and typically saves roughly 24 to 28 percent compared to paying month to month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d7e53a2-7024-463c-8941-1eaf38f894b8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Unified Logs, Traces and Metrics Search$q$, $q$Search and correlate logs, traces, metrics, and exceptions from a single interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Session Replay Correlated with Traces$q$, $q$See exactly what a user experienced in the browser alongside the matching backend traces and errors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$OpenTelemetry-Native Ingestion$q$, $q$Ingest data via the standard OpenTelemetry Collector without proprietary re-instrumentation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$ClickHouse-Powered Storage and Query Engine$q$, $q$Store and query observability data on ClickHouse for fast performance at large data volumes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Pre-Built Dashboards and Alerting$q$, $q$Visualize key metrics out of the box and alert via Slack, PagerDuty, or custom webhooks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Self-Hostable via Docker and Kubernetes$q$, $q$Run HyperDX entirely on your own infrastructure and ClickHouse cluster for full control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Usage-Based Pricing$q$, $q$Pay based on data volume ingested rather than per-seat or per-host fees.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Exception and Error Tracking$q$, $q$Automatically capture and surface application exceptions alongside related traces and logs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Fully open source and self-hostable under MIT and Apache 2.0 licenses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$ClickHouse backend delivers fast queries even at very large log and trace volumes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Usage-based pricing avoids expensive per-seat or per-host costs common at competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Unifies logs, traces, metrics, and session replay in one interface instead of separate tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Backed by ClickHouse Inc.'s engineering resources following the 2025 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Newer platform with a smaller overall feature set than mature vendors like Datadog or New Relic$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Self-hosting requires operating and maintaining a ClickHouse cluster$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Free tier retention is limited to just 3 days, which may be too short for some teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Documentation and ecosystem are still maturing following the ClickHouse acquisition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Fewer pre-built third-party integrations than long-established observability vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Is HyperDX free?$q$, $q$Yes, HyperDX offers a Free tier with 3 GB of data per month and 3-day retention. Paid plans start at $20 per month for 50 GB of data with 30-day retention and unlimited users.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$What database does HyperDX use?$q$, $q$HyperDX is built on ClickHouse, the open-source columnar analytics database, using it as the storage and query engine for logs, traces, and metrics.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Who created HyperDX and what happened after the ClickHouse acquisition?$q$, $q$HyperDX was founded in 2022 by Warren Lee and Michael Shi. In March 2025, ClickHouse Inc. acquired HyperDX, and its technology now underpins ClickStack, ClickHouse's official open-source observability stack, while HyperDX Cloud continues operating.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Can I self-host HyperDX?$q$, $q$Yes, HyperDX can be fully self-hosted via Docker or Kubernetes on your own ClickHouse cluster under its MIT and Apache 2.0 open-source licenses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$How is HyperDX priced?$q$, $q$HyperDX uses usage-based pricing based on data volume ingested, with no per-seat or per-host fees, starting free and scaling to a flat $20 per month Starter plan and custom Enterprise pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Does HyperDX replace Datadog?$q$, $q$HyperDX can replace many Datadog use cases around logs, traces, metrics, and session replay for teams wanting an open-source, self-hostable, usage-priced alternative, though Datadog offers a broader and more mature integration ecosystem.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Debugging Production Incidents$q$, $q$Correlate logs, traces, and session replay in one place to quickly find the root cause of an outage.$q$, $q$Backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Self-Hosted Observability on Existing Infrastructure$q$, $q$Run observability entirely on a team's own ClickHouse cluster for cost and data control.$q$, $q$Platform and SRE teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Cost-Sensitive Observability at Scale$q$, $q$Monitor growing data volumes without per-host or per-seat pricing eating into infrastructure budgets.$q$, $q$Startups scaling data volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["3 GB/month data","3-day retention","1 user","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Starter$q$, $q$$20/month$q$, $q$Monthly$q$, NULL, $q$["50 GB/month included","30-day retention","Unlimited users","$0.40 per additional GB"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Custom contracts and retention","SAML SSO","Volume discounts","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HyperDX is an open-source observability platform that unifies logs, traces, metrics, exceptions, and session replay in one tool, built on OpenTelemetry and ClickHouse. Founded in 2022 by Warren Lee and Michael Shi as a Y Combinator-backed startup in San Francisco, HyperDX set out to give engineering teams Datadog-level visibility without Datadog-level cost.$q$, $q$In March 2025, ClickHouse Inc. acquired HyperDX, folding its technology into ClickStack, ClickHouse's official open-source observability stack, while HyperDX Cloud continues to operate as a hosted product. The acquisition gave HyperDX's technology the backing and long-term engineering resources of the company that builds the ClickHouse database itself.$q$, $q$The platform can be fully self-hosted on a team's own ClickHouse cluster via Docker or Kubernetes, or consumed as a managed cloud SaaS, giving engineering teams flexibility between infrastructure control and operational convenience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HyperDX provides a unified search interface spanning logs, traces, metrics, and exceptions, backed by ClickHouse's columnar query engine, which allows fast aggregate queries even over very large data volumes that would be slow or costly in traditional observability backends.$q$, $q$Session replay is tightly correlated with backend traces, letting engineers see exactly what a user experienced in the browser alongside the corresponding server-side errors and requests, which speeds up root-cause analysis for production incidents.$q$, $q$Native OpenTelemetry Collector compatibility means teams with existing OTel instrumentation can adopt HyperDX without re-instrumenting applications, while built-in alerting integrations with Slack, PagerDuty, and webhooks keep teams notified of issues in real time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d0fed099-679d-4702-a509-fbb8a5115476', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HyperDX prices based on data usage rather than per-seat or per-host billing, a deliberate departure from traditional observability vendors. The Free tier includes 3 GB of data per month with 3-day retention and 1 user, letting small teams or side projects try the platform at no cost, while the Starter plan is a flat $20 per month for 50 GB of data with 30-day retention and unlimited users, with overage priced at $0.40 per additional GB and $0.40 per 100 metrics at 1 data point per minute.$q$, $q$Larger organizations move to the custom-priced Enterprise tier, which offers negotiated contracts, custom retention periods, SAML single sign-on, and volume discounts for high-scale deployments, making HyperDX's pricing model scale from hobby projects up to large production environments without requiring a per-seat license at any tier.$q$]::text[], 2);
